#include "interface.h"

#include <cstdint>
#include <string>
#include <vector>

uint64_t dictionary_prefix_weight_sum(
    const std::vector<std::string>& dictionary,
    const std::vector<uint16_t>& codes,
    const std::vector<uint32_t>& weights,
    int iters) {
  (void)iters;
  // Precompute which dictionary entries match the prefix.
  std::vector<uint8_t> match(dictionary.size(), 0);
  for (std::size_t i = 0; i < dictionary.size(); ++i) {
    const std::string& s = dictionary[i];
    if (s.size() >= 2 && s[0] == 'q' && s[1] <= 'm') {
      match[i] = 1;
    }
  }
  // Single pass over codes, sum weights where dictionary entry matches.
  uint64_t sum = 0;
  for (std::size_t i = 0; i < codes.size(); ++i) {
    if (match[codes[i]]) {
      sum += static_cast<uint64_t>(weights[i]);
    }
  }
  return sum;
}
